function changeLanguage(e){const t=translations[e];if(!t)return;TEXT_KEYS.forEach(e=>{document.getElementById(e).textContent=t[e]});const i=document.getElementById("aboutimg");i&&(i.src=t.imgSrc1,i.alt=t.imgAlt1);const m=document.getElementById("projecimg");m&&(m.src=t.imgSrc2,m.alt=t.imgAlt2),document.documentElement.lang=e}const translations={pt:{dividertext:"o sonho de manter a internet viva segue vivo.",whatsapp:"me mande uma mensagem.",telainicial:"tela inicial",projc:"projetos",sobremim:"sobre mim",imgSrc1:"../img/texto.svg",imgAlt1:"sobre mim",imgSrc2:"../img/Projetos.svg",imgAlt2:"meus projetos"},en:{dividertext:"the dream of keeping the internet alive remains alive.",whatsapp:"send me a message.",telainicial:"homepage",projc:"projects",sobremim:"about me",imgSrc1:"../img/texto-eng.svg",imgAlt1:"about me",imgSrc2:"../img/Projetoseng.svg",imgAlt2:"my projects"}},TEXT_KEYS=["dividertext","whatsapp","telainicial","projc","sobremim"];document.getElementById("language-selector").addEventListener("change",e=>{changeLanguage(e.target.value)});